(()=>{'use strict';const base='/DraBornGarage/assets/chunks_v3/';const modules=[['dkd_core.js',Array.from({length:10},(_,i)=>`core_${String(i).padStart(3,'0')}.txt`)],['dkd_customer.js',Array.from({length:5},(_,i)=>`customer_${String(i).padStart(3,'0')}.txt`)],['dkd_staff.js',Array.from({length:12},(_,i)=>`staff_${String(i).padStart(3,'0')}.txt`)],['dkd_garage.js',['garage_000.txt']]];async function inflate(encoded){const bytes=Uint8Array.from(atob(encoded),c=>c.charCodeAt(0));if(!('DecompressionStream'in window))throw new Error('Tarayıcınız DraBornGarage web paketini açmak için çok eski.');return new Response(new Blob([bytes]).stream().pipeThrough(new DecompressionStream('gzip'))).text()}(async()=>{for(const[name,chunks]of modules){let encoded='';for(const chunk of chunks){const response=await fetch(base+chunk,{cache:'no-cache'});if(!response.ok)throw new Error(`${name} paketi yüklenemedi (${response.status}).`);encoded+=(await response.text()).trim()}const source=await inflate(encoded);(0,eval)(`${source}\n//# sourceURL=/DraBornGarage/assets/${name}`)}})().catch(error=>{console.error(error);const app=document.getElementById('dkd-app');if(app)app.innerHTML=`<div class="dkd-section"><div class="dkd-empty"><div class="ico">⚠</div><h1>Web paketi açılamadı</h1><p>${String(error.message||error)}</p><button class="dkd-btn" onclick="location.reload()">Tekrar Dene</button></div></div>`})})();
